function parseCssVariables(css: string) {
  const variables: Record<string, string> = {};
  const regex = /(--[^:]+):\s*([^;]+);/g;
  let match: RegExpExecArray | null;
  while ((match = regex.exec(css)) !== null)
    variables[match[1]] = match[2].trim();
  return variables;
}

function updateCssVariable(css: string, variableName: string, value: string) {
  const declaration = `${variableName}: ${value};`;
  const variableRegex = new RegExp(
    `${variableName.replace(/[.*+?^${}()|[\]\\]/g, "\\$&")}\\s*:\\s*[^;]+;`
  );
  if (variableRegex.test(css)) return css.replace(variableRegex, declaration);
  if (/:root\s*{/.test(css))
    return css.replace(/:root\s*{/, `:root {\n  ${declaration}`);
  return `:root {\n  ${declaration}\n}\n\n${css}`;
}

function rgbSpaceToHex(value?: string) {
  if (!value) return "#000000";
  const parts = value
    .match(/\d+(?:\.\d+)?/g)
    ?.slice(0, 3)
    .map(part => Math.max(0, Math.min(255, Number(part)))) || [0, 0, 0];
  return `#${parts.map(part => Math.round(part).toString(16).padStart(2, "0")).join("")}`;
}

function hexToRgbSpace(hex: string) {
  const clean = hex.replace("#", "");
  const value =
    clean.length === 3
      ? clean
          .split("")
          .map(item => item + item)
          .join("")
      : clean;
  const int = Number.parseInt(value, 16);
  if (Number.isNaN(int)) return "0 0 0";
  return `${(int >> 16) & 255} ${(int >> 8) & 255} ${int & 255}`;
}

function isColorValue(value?: string) {
  return Boolean(
    value && /^\s*\d+(?:\.\d+)?\s+\d+(?:\.\d+)?\s+\d+(?:\.\d+)?\s*$/.test(value)
  );
}

function splitSelectorList(selectorText: string) {
  const selectors: string[] = [];
  let current = "";
  let depth = 0;
  for (const char of selectorText) {
    if (char === "(" || char === "[") depth += 1;
    if (char === ")" || char === "]") depth = Math.max(0, depth - 1);
    if (char === "," && depth === 0) {
      if (current.trim()) selectors.push(current.trim());
      current = "";
      continue;
    }
    current += char;
  }
  if (current.trim()) selectors.push(current.trim());
  return selectors;
}

function stripSelectorState(selector: string) {
  return selector
    .replace(/::[a-zA-Z-]+/g, "")
    .replace(
      /:(hover|focus|focus-visible|focus-within|active|visited|disabled|enabled|checked|selected|open|first-child|last-child|first-of-type|last-of-type|empty|root)\b/g,
      ""
    )
    .trim();
}

function safelyMatches(element: HTMLElement, selector: string) {
  try {
    return element.matches(selector);
  } catch {
    const stripped = stripSelectorState(selector);
    if (!stripped || stripped === selector) return false;
    try {
      return element.matches(stripped);
    } catch {
      return false;
    }
  }
}

function inspectElementsFor(element: HTMLElement) {
  const elements: HTMLElement[] = [];
  let current: HTMLElement | null = element;
  while (current && elements.length < 8) {
    elements.push(current);
    if (
      current.id === "dex-preview-root" ||
      current.classList.contains("orderly-app-container")
    )
      break;
    current = current.parentElement;
  }
  element.querySelectorAll("*").forEach(child => {
    if (elements.length < 120 && child instanceof HTMLElement)
      elements.push(child);
  });
  return elements;
}

function collectCssRules(sheet: CSSStyleSheet, rules: CSSStyleRule[]) {
  let cssRules: CSSRuleList;
  try {
    cssRules = sheet.cssRules;
  } catch {
    return;
  }
  Array.from(cssRules).forEach(rule => {
    if (rule instanceof CSSStyleRule) {
      rules.push(rule);
      return;
    }
    const nestedRules = (rule as CSSGroupingRule).cssRules;
    if (!nestedRules) return;
    Array.from(nestedRules).forEach(nestedRule => {
      if (nestedRule instanceof CSSStyleRule) rules.push(nestedRule);
    });
  });
}

function extractRuleVariables(rule: CSSStyleRule) {
  const variables = new Set<string>();
  const cssText = `${rule.cssText || ""} ${rule.style?.cssText || ""}`;
  const variableRegex = /var\(\s*(--oui-[a-zA-Z0-9-]+)/g;
  let match: RegExpExecArray | null;
  while ((match = variableRegex.exec(cssText)) !== null)
    variables.add(match[1]);
  return variables;
}

function normalizeRgbValue(value: string) {
  if (
    !value ||
    value === "transparent" ||
    /rgba\([^)]*,\s*0\s*\)$/i.test(value)
  )
    return null;
  const parts = value
    .match(/\d+(?:\.\d+)?/g)
    ?.slice(0, 3)
    .map(part => Math.round(Number(part)));
  if (!parts || parts.length < 3 || parts.some(part => !Number.isFinite(part)))
    return null;
  return parts.join(" ");
}

function extractThemeVariablesFromElement(
  element: HTMLElement,
  themeCSS: string
) {
  const discovered = new Set<string>();
  const elements = inspectElementsFor(element);
  const rules: CSSStyleRule[] = [];
  const rootNode = element.getRootNode();

  if (rootNode instanceof ShadowRoot) {
    rootNode.querySelectorAll("style").forEach(style => {
      if (style.sheet) collectCssRules(style.sheet, rules);
    });
  }
  Array.from(document.styleSheets).forEach(sheet =>
    collectCssRules(sheet, rules)
  );

  rules.forEach(rule => {
    const ruleVariables = extractRuleVariables(rule);
    if (!ruleVariables.size) return;
    const matchesRule = splitSelectorList(rule.selectorText).some(selector =>
      elements.some(item => safelyMatches(item, selector))
    );
    if (matchesRule)
      ruleVariables.forEach(variableName => discovered.add(variableName));
  });

  const themeVariables = parseCssVariables(themeCSS);
  const colorToVariables = new Map<string, string[]>();
  THEME_VARIABLES.forEach(variableName => {
    const value = themeVariables[variableName];
    if (!isColorValue(value)) return;
    const normalized = normalizeRgbValue(value);
    if (!normalized) return;
    colorToVariables.set(normalized, [
      ...(colorToVariables.get(normalized) || []),
      variableName,
    ]);
  });

  const colorProperties = [
    "color",
    "backgroundColor",
    "borderTopColor",
    "borderRightColor",
    "borderBottomColor",
    "borderLeftColor",
    "outlineColor",
    "fill",
    "stroke",
    "caretColor",
  ] as const;
  elements.slice(0, 12).forEach(item => {
    const style = item.ownerDocument.defaultView?.getComputedStyle(item);
    if (!style) return;
    colorProperties.forEach(property => {
      const normalized = normalizeRgbValue(style[property]);
      if (!normalized) return;
      colorToVariables
        .get(normalized)
        ?.forEach(variableName => discovered.add(variableName));
    });
  });

  return Array.from(discovered).filter(variableName =>
    THEME_VARIABLES.includes(variableName)
  );
}

function getThemeSwatches(css: string) {
  const vars = parseCssVariables(css);
  return [
    vars["--oui-color-base-10"],
    vars["--oui-color-base-7"],
    vars["--oui-color-primary"],
    vars["--oui-color-trading-profit"],
    vars["--oui-color-trading-loss"],
  ]
    .filter(Boolean)
    .map(rgbSpaceToHex);
}

async function appendDataUrlFile(
  formData: FormData,
  key: string,
  value: string | null,
  filename: string
) {
  if (!value || !value.startsWith("data:")) return;
  const blob = await fetch(value).then(response => response.blob());
  formData.append(key, blob, filename);
}

function isValidUrl(value: string) {
  const trimmed = value.trim();
  if (!trimmed) return true;
  try {
    const url = new URL(trimmed);
    return url.protocol === "http:" || url.protocol === "https:";
  } catch {
    return false;
  }
}

function isBuilderNameComplete(value: string) {
  const trimmed = value.trim();
  return (
    trimmed.length >= 3 &&
    trimmed.length <= 30 &&
    /^[a-zA-Z0-9 .\-_]*$/.test(trimmed)
  );
}

function validateSeo(form: DexConfigForm) {
  if (form.seoSiteName.length > 100)
    return "SEO site name must be 100 characters or less.";
  if (form.seoSiteDescription.length > 300)
    return "SEO description must be 300 characters or less.";
  if (form.seoKeywords.length > 500)
    return "SEO keywords must be 500 characters or less.";
  if (
    form.seoSiteLanguage.trim() &&
    !/^[a-z]{2}(-[A-Z]{2})?$/.test(form.seoSiteLanguage.trim())
  )
    return "SEO language must use a format like en or en-US.";
  if (
    form.seoSiteLocale.trim() &&
    !/^[a-z]{2}_[A-Z]{2}$/.test(form.seoSiteLocale.trim())
  )
    return "SEO locale must use a format like en_US.";
  if (
    form.seoTwitterHandle.trim() &&
    !/^@[a-zA-Z0-9_]+$/.test(form.seoTwitterHandle.trim())
  )
    return "SEO Twitter handle must start with @ and contain only letters, numbers, or underscores.";
  if (
    form.seoThemeColor.trim() &&
    !/^#[0-9A-Fa-f]{6}$/.test(form.seoThemeColor.trim())
  )
    return "SEO theme color must be a hex color like #1a1b23.";
  return null;
}

function parseCustomMenus(value: string): CustomMenuItem[] {
  if (!value.trim()) return [];
  return value
    .split(";")
    .map(entry => entry.trim())
    .filter(Boolean)
    .map(entry => {
      const [name = "", ...urlParts] = entry.split(",");
      return { name: name.trim(), url: urlParts.join(",").trim() };
    });
}

function serializeCustomMenus(items: CustomMenuItem[]) {
  return items
    .filter(item => item.name.trim() || item.url.trim())
    .map(item => `${item.name.trim()}, ${item.url.trim()}`)
    .join("; ");
}

function validateCustomMenus(value: string) {
  const items = parseCustomMenus(value);
  for (const item of items) {
    if (!item.name || !item.url)
      return "Each custom menu needs both a name and URL.";
    if (item.name.length > 24)
      return "Custom menu names must be 24 characters or less.";
    if (!isValidUrl(item.url))
      return "Custom menu URLs must be valid http(s) URLs.";
  }
  return null;
}

function hasText(...values: Array<string | null | undefined>) {
  return values.some(value => Boolean(value?.trim()));
}

function statusForOptionalInput(
  hasInput: boolean,
  reviewNote?: string | null
): SectionStatus {
  if (!hasInput) return OPTIONAL_SECTION_STATUS;
  return reviewNote
    ? { done: false, label: "Review", note: reviewNote, tone: "review" }
    : DONE_SECTION_STATUS;
}

function symbolVolume(row: FuturesRow) {
  const volume = Number(row["24h_volume"] ?? row.volume_24h ?? 0);
  const price = Number(row.index_price ?? 0);
  return (
    (Number.isFinite(volume) ? volume : 0) *
    (Number.isFinite(price) ? price : 0)
  );
}

function selectedSymbolSet(symbolList: string) {
  return new Set(
    symbolList
      .split(",")
      .map(item => item.trim())
      .filter(Boolean)
  );
}

function joinSymbols(symbols: Set<string>) {
  return Array.from(symbols).sort().join(",");
}

function getElementLabel(element: HTMLElement) {
  const tag = element.tagName.toLowerCase();
  const className = String(element.className || "")
    .split(" ")
    .filter(Boolean)
    .slice(0, 2)
    .join(".");
  const text = element.textContent?.trim().replace(/\s+/g, " ").slice(0, 36);
  return `${tag}${className ? `.${className}` : ""}${text ? `, ${text}` : ""}`;
}

function reorder<T>(items: T[], from: number, to: number) {
  const next = [...items];
  const [item] = next.splice(from, 1);
  next.splice(to, 0, item);
  return next;
}

function SectionCard({
  id,
  icon,
  title,
  description,
  children,
  isOpen,
  onToggle,
  status,
  required,
}: {
  id: string;
  icon: React.ReactNode;
  title: string;
  description: string;
  children: React.ReactNode;
  isOpen: boolean;
  onToggle: () => void;
  status: SectionStatus;
  required?: boolean;
}) {
  const pillLabel = status.done
    ? "Done"
    : status.tone === "review"
      ? "Review"
      : required
        ? "Required"
        : "Optional";
  const pillTone = status.done
    ? "done"
    : status.tone === "review"
      ? "review"
      : required
        ? "required"
        : "optional";
  const statusClass =
    pillTone === "done"
      ? "border-[rgba(41,233,169,0.32)] bg-[rgba(41,233,169,0.10)] text-[rgb(41,233,169)]"
      : pillTone === "required"
        ? "border-[rgba(255,209,70,0.32)] bg-[rgba(255,209,70,0.10)] text-[rgb(255,209,70)]"
        : pillTone === "optional"
          ? "border-(--line-subtle) bg-(--bg-surface-secondary) text-(--fg-secondary)"
          : "border-[rgba(245,97,139,0.32)] bg-[rgba(245,97,139,0.10)] text-[rgb(245,97,139)]";

  return (
    <section
      id={id}
      className="scroll-mt-6 overflow-hidden rounded-2xl border border-(--line-subtle) bg-(--bg-surface-primary) shadow-[0_18px_54px_rgba(0,0,0,0.14)]"
    >
      <button
        type="button"
        aria-expanded={isOpen}
        aria-controls={`${id}-content`}
        onClick={onToggle}
        className="flex w-full items-start justify-between gap-4 border-b border-(--line-subtle) bg-[rgba(255,255,255,0.015)] px-5 py-4 text-left transition-colors hover:bg-[rgba(255,255,255,0.025)]"
      >
        <div className="flex min-w-0 items-start gap-3">
          <div
            className={`mt-0.5 flex h-9 w-9 shrink-0 items-center justify-center rounded-[10px] bg-(--bg-hover) ${status.done ? "text-(--line-positive)" : "text-(--fg-brand)"}`}
          >
            {status.done ? <DoneSectionIcon id={id} /> : icon}
          </div>
          <div className="min-w-0">
            <div className="flex flex-wrap items-center gap-2">
              <h2 className="text-base font-semibold tracking-[-0.01em] text-(--fg-primary)">
                {title}
              </h2>
              <span
                title={status.note}
                className={`inline-flex items-center gap-1 rounded-full border px-2 py-0.5 text-[11px] font-medium ${statusClass}`}
              >
                {pillLabel}
              </span>
            </div>
            <p className="mt-1 max-w-3xl text-sm leading-6 text-(--fg-secondary)">
              {description}
            </p>
            {!status.done && status.tone !== "optional" && (
              <p className="mt-1 text-xs text-(--fg-secondary)">
                {status.note}
              </p>
            )}
          </div>
        </div>
        <ChevronDown
          className={`mt-1 h-5 w-5 shrink-0 text-(--fg-secondary) transition-transform ${isOpen ? "rotate-180" : ""}`}
        />
      </button>
      <div id={`${id}-content`} className={isOpen ? "p-5" : "hidden"}>
        {children}
      </div>
    </section>
  );
}

