function ThemeCustomizationSection({
  form,
  updateForm,
  showToast,
}: {
  form: DexConfigForm;
  updateForm: (patch: Partial<DexConfigForm>) => void;
  showToast: (message: string) => void;
}) {
  const { t } = useTranslation();
  const [editMode, setEditMode] = useState<ThemeMode | null>(null);
  const [modal, setModal] = useState<ThemeModal>(null);
  const [aiPrompt, setAiPrompt] = useState("");
  const [generatedThemes, setGeneratedThemes] = useState<string[]>([]);
  const [selectedGeneratedTheme, setSelectedGeneratedTheme] = useState(0);
  const [generating, setGenerating] = useState(false);
  const themeCSS = form.themeCSS || DEFAULT_THEME;
  const isCssDisabled = !CUSTOM_CSS_FEATURE_ENABLED;

  async function generateTheme(prompt: string, mode: ThemeMode) {
    const trimmed = prompt.trim();
    if (!trimmed || generating) return;
    setGenerating(true);
    try {
      const themes = await modifyDexCreatorTheme(trimmed, themeCSS);
      setGeneratedThemes(themes.slice(0, 3));
      setSelectedGeneratedTheme(0);
      setModal({ type: "generated", mode });
    } catch (error) {
      showToast(
        error instanceof Error
          ? error.message
          : "Failed to generate theme variants."
      );
    } finally {
      setGenerating(false);
    }
  }

  return (
    <div className="space-y-5">
      {isCssDisabled && (
        <div className="rounded-lg border border-yellow-500/30 bg-yellow-500/10 px-3 py-2 text-xs text-yellow-100">
          {t("featureFlags.customCssDisabled")}
        </div>
      )}
      <div>
        <h3 className="text-sm font-semibold text-(--fg-primary)">
          Interactive preview
        </h3>
        <p className="mt-1 text-sm text-(--fg-secondary)">
          This matches dex-creator: open desktop or mobile edit mode, then use
          presets, theme, AI, or Ctrl/Command-click inspection against the real
          Orderly SDK preview.
        </p>
      </div>
      <div className="grid grid-cols-1 gap-4 lg:grid-cols-2">
        <PreviewEntryCard
          mode="desktop"
          onOpen={() => setEditMode("desktop")}
          disabled={isCssDisabled}
        />
        <PreviewEntryCard
          mode="mobile"
          onOpen={() => setEditMode("mobile")}
          disabled={isCssDisabled}
        />
      </div>
      <div
        className={`rounded-lg border border-(--line-subtle) bg-(--bg-surface-secondary) p-4 ${isCssDisabled ? "pointer-events-none opacity-60" : ""}`}
      >
        <FieldLabel label="AI theme generator" hint="Generate three variants" />
        <TextArea
          value={aiPrompt}
          onChange={event => setAiPrompt(event.target.value)}
          rows={3}
          maxLength={100}
          className="mt-2"
          placeholder="Example: dark cobalt terminal with cyan accents"
          readOnly={isCssDisabled}
        />
        <button
          type="button"
          disabled={!aiPrompt.trim() || generating || isCssDisabled}
          onClick={() => void generateTheme(aiPrompt, "desktop")}
          className="mt-3 rounded-full px-4 py-2 text-sm font-medium text-(--fg-primary) transition-opacity hover:opacity-90 disabled:cursor-not-allowed disabled:opacity-50"
          style={{ background: "var(--bg-brand-grad)" }}
        >
          {generating ? "Generating..." : "Generate theme"}
        </button>
      </div>
      {editMode && (
        <PreviewPortal>
          <EditModeModal
            mode={editMode}
            form={form}
            onClose={() => setEditMode(null)}
            onThemeChange={themeCSS => updateForm({ themeCSS })}
            onOpenModal={setModal}
          />
        </PreviewPortal>
      )}
      {modal?.type === "presets" && (
        <PreviewPortal>
          <ThemePresetModal
            mode={modal.mode}
            form={form}
            onClose={() => setModal(null)}
            onApply={themeCSS => {
              updateForm({ themeCSS });
              setModal(null);
            }}
          />
        </PreviewPortal>
      )}
      {modal?.type === "theme" && (
        <PreviewPortal>
          <ThemeEditorModal
            mode={modal.mode}
            form={form}
            onClose={() => setModal(null)}
            onChange={updateForm}
          />
        </PreviewPortal>
      )}
      {modal?.type === "ai" && (
        <PreviewPortal>
          <AIThemeModal
            mode={modal.mode}
            prompt={aiPrompt}
            generating={generating}
            onPromptChange={setAiPrompt}
            onClose={() => setModal(null)}
            onGenerate={prompt => void generateTheme(prompt, modal.mode)}
          />
        </PreviewPortal>
      )}
      {modal?.type === "generated" && (
        <PreviewPortal>
          <GeneratedThemeModal
            mode={modal.mode}
            form={form}
            themes={generatedThemes}
            selectedIndex={selectedGeneratedTheme}
            onSelect={setSelectedGeneratedTheme}
            onBack={() => setModal({ type: "ai", mode: modal.mode })}
            onClose={() => setModal(null)}
            onApply={themeCSS => {
              updateForm({ themeCSS });
              setModal(null);
            }}
          />
        </PreviewPortal>
      )}
    </div>
  );
}

